The addition of the timeStamp member to the STCAN_MSG class on the node simulation side, broke the ability to access the isCanfd (m_bCANFD) member from the DIL side.  I have added CAN-FD support to the CAN_PEAK_USB DIL, but the STCAN_MSG class byte alignment needs to be equal on both sides in order for all of the members to be accessible from both sides.

The compiler fixes the alignment differences between bool and unsigned char for isRtr and isExtended, but I changed them anyway just for good measure.

```
diff --git a/Sources/BUSMASTER/Application/SimulatedSystems/include/BMCANDefines.h b/Sources/BUSMASTER/Application/SimulatedSystems/include/BMCANDefines.h
index 1ec93da..fa25491 100644
--- a/Sources/BUSMASTER/Application/SimulatedSystems/include/BMCANDefines.h
+++ b/Sources/BUSMASTER/Application/SimulatedSystems/include/BMCANDefines.h
@@ -20,8 +20,8 @@ class STCAN_MSG
 {
 public:
     unsigned int id;        // 11/29 Bit-
-    bool isExtended; // true, for (29 Bit) Frame Standard/Extended
-    bool isRtr;    // true, for remote request
+    unsigned char isExtended; // true, for (29 Bit) Frame Standard/Extended
+    unsigned char isRtr;    // true, for remote request
     unsigned char dlc;      // Data length (0..8)
     unsigned char cluster;
     unsigned char data[64];
diff --git a/Sources/Kernel/BusmasterDriverInterface/Include/CANDriverDefines.h b/Sources/Kernel/BusmasterDriverInterface/Include/CANDriverDefines.h
index fd5ed06..43ae67f 100644
--- a/Sources/Kernel/BusmasterDriverInterface/Include/CANDriverDefines.h
+++ b/Sources/Kernel/BusmasterDriverInterface/Include/CANDriverDefines.h
@@ -139,6 +139,7 @@ public:
     /** Databytes 0..63 */
     unsigned char m_ucData[64];

+       unsigned long m_ultimeStamp;
     /* CAN FD frame */
     bool m_bCANFD;
 } ;
```

