I am now using a windows shared memory mechanism in place of the clumsy file I/O solution.  I add the following DLL handlers to all simulated nodes.  The first one started creates the shared memory, the rest map to it.  lpvMem becomes global to all node simulation DLLs:
```
void OnDLL_Load()
{
	Trace("CAN dll loaded");
	hMapObject = CreateFileMapping( 
                INVALID_HANDLE_VALUE,   // use paging file
                NULL,                   // default security attributes
                PAGE_READWRITE,         // read/write access
                0,                      // size: high 32-bits
                SHMEMSIZE,              // size: low 32-bits
                TEXT("bmdllmemfilemap")); // name of map object
 
	// The first process to attach initializes memory
	fInit = (GetLastError() != ERROR_ALREADY_EXISTS); 

	// Get a pointer to the file-mapped shared memory
	lpvMem = MapViewOfFile( 
                hMapObject,     // object to map view of
                FILE_MAP_WRITE, // read/write access
                0,              // high offset:  map from
                0,              // low offset:   beginning
                0);             // default: map entire file

	// Initialize memory if this is the first process
 
	if (fInit) {
		memset(lpvMem, '\0', SHMEMSIZE); 
		Trace("shared memory created by CAN dll");
	}
}/* End BUSMASTER generated function - OnDLL_Load */
/* Start BUSMASTER generated function - OnDLL_Unload */
void OnDLL_Unload()
{
	fIgnore = UnmapViewOfFile(lpvMem);
	fIgnore = CloseHandle(hMapObject);
}/* End BUSMASTER generated function - OnDLL_Unload */
```

